var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래시포드 씨, 이건 어때요? 그럴싸하게 생기지 않았어요?","JPN":"ラッシュフォードさん、これはどうですか？　それっぽくないですか？","ENG":"Miss Rashford, what about this? It kind of looks like a relic, no?","TWN":"雷斯福特，這個怎麼樣？不覺得很像嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"글쎄요. 그냥 불에 녹은 냄비로 보입니다만.","JPN":"どうでしょう。ただ火で溶けた鍋にしか見えませんが。","ENG":"Hmm... It just looks like a melted pot to me.","TWN":"這個嘛，看起來像是被火融化的鍋子。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"그러면 이건요?","JPN":"じゃあ、これは？","ENG":"Then what about this one?","TWN":"那這個呢？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아무리 그래도 밑창 떨어진 구두가 성유물일 것 같진 않군요.","JPN":"いくらなんでも底の抜けた靴が聖遺物ではないでしょう。","ENG":"I don't see how the sole of a shoe can be a Holy Relic.","TWN":"再怎麼說，鞋底壞掉的皮鞋應該不會是聖遺物吧？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"휴우……. 어떻게 생겼는지도 모르니까 찾기가 쉽지 않네요.","JPN":"ふう……どんな形をしてるのかわからないから、探すのに苦労しますね。","ENG":"*Sigh...* It's difficult to find something when we don't know what it's supposed to look like.","TWN":"呼……又不知道長什麼樣，是要怎麼找啦！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"여기 쌓여 있는 돌무더기나 나뭇가지 중 하나가 성유물이면 어쩌죠?","JPN":"ここに積もってる石ころとか木の枝一本が聖遺物だったらどうしましょう？","ENG":"What if it's one of these rocks or twigs piled up here?","TWN":"要這堆石頭或樹枝中，有一個是聖遺物的話怎麼辦？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관, 혹시 성유물의 생김새에 대해 짐작가는 바가 없나?","JPN":"指揮官、聖遺物の外見について思い当たることはないか？","ENG":"Commander. Can you remember anything about what the Holy Relic looks like?","TWN":"指揮官，你對於聖遺物的外觀有什麼想法嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"죄송합니다. 지금으로선 아무런 단서도 떠오르지 않는군요.","JPN":"申し訳ありません。現時点ではなんの手がかりも思い浮びませんね。","ENG":"Sorry. Nothing comes to mind right now.","TWN":"對不起，我現在一點頭緒都沒有。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런가. 하긴 괜한 질문이었군.","JPN":"そうか。まあ、余計な質問だったか。","ENG":"I see. Forget that I asked.","TWN":"是嗎？也是，我不該問你的。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어라? 래시포드 씨, 그걸 왜 지휘관님에게 물어보세요?","JPN":"あれ？　ラッシュフォードさん、どうしてそれを指揮官に聞くんですか？","ENG":"Huh? Miss Rashford? Why did you ask that to the Commander?","TWN":"嗯？雷斯福特，你為什麼問指揮官？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아, 별거 아닙니다. 머리를 맞대고 고민해 보면 참신한 발상이 떠오를지도 모르니까요.","JPN":"あ、大したことではありません。額を集めて悩んでみると、斬新なアイデアが浮かび上がるかもしれませんから。","ENG":"Oh, it's nothing. I was just thinking that if we put our heads together we might get an idea.","TWN":"喔，沒什麼，想說彼此腦力激盪的話，或許會有什麼新的想法。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"앗, 그렇네요!","JPN":"あっ、そうですね！","ENG":"Oh, I see!","TWN":"喔，原來是這樣！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"병사 여러분도 그럴싸한 물건을 발견하면 언제든 말씀해 주세요!","JPN":"兵士のみなさんもそれっぽいものを発見したらいつでも話してください！","ENG":"If you find something that could be the relic, please don't hesitate show us!","TWN":"各位士兵，如果有發現什麼類似的東西，請隨時告訴我！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"이건 어떻습니까?","JPN":"これはどうでしょう？","ENG":"What about this?","TWN":"這個怎麼樣？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어머, 신기하게 생긴 문고리네요.","JPN":"あら、不思議な取っ手ですね。","ENG":"Oh my. That's an odd looking door handle.","TWN":"哇，長得好特別的門把。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"저도 특이하게 생긴 걸 주웠습니다만, 한 번 봐 주시겠습니까?","JPN":"俺も変わった形をしたものを拾いましたが、見てもらえますか？","ENG":"I found this strange thing. Do you think this could be it?","TWN":"我也撿到一個長得很特別的東西，可以看一下嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"으음~ 녹은 못이 뭉쳐서 굳은 것 같은데, 혹시 모르니 그것도 가져가 볼까요?","JPN":"うーん、溶けた釘が集まって固まったもののようですけど、念のためそれも持っていきましょうか？","ENG":"Um... I think that's just a bunch of melted nails, but bring it along just it case.","TWN":"嗯～好像是釘子融化後又結塊的樣子，以防萬一，那個也拿走吧！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"}}}}]`);export{e as default};